arguments.file_text:
namespace sv_e2fd2580af504b2bbc9888ebf0bb5b23.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@using sv_e2fd2580af504b2bbc9888ebf0bb5b23.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ───── Left Sidebar: Channel List ───── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var ch in _channels)
                {
                    <li class="channel-item @(ch.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch)">
                        <div class="channel-name"># @ch.Name</div>
                        <div class="channel-desc">@Truncate(ch.Description, 40)</div>
                        @if (ch.UnreadCount > 0)
                        {
                            <span class="unread-badge">@ch.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ───── Main Message Area ───── *@
    <section class="message-area @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h2># @_activeChannel.Name</h2>
                <span class="channel-description">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScroll">
                @if (_loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-meta">
                                <span class="author">@msg.Author</span>
                                <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-content">@msg.Content</div>

                            @* Reactions *@
                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ToggleReactionAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @* Thread replies link *@
                            @{
                                var summary = _threadSummaries.GetValueOrDefault(msg.Id);
                            }
                            @if (summary is not null)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                    — last @FormatRelativeTime(summary.LastReplyAt)
                                </button>
                            }

                            @* Hover actions *@
                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread" @onclick="() => OpenThreadAsync(msg)">
                                        💬 Reply
                                    </button>
                                    <button class="action-btn" title="Add reaction" @onclick="() => ToggleEmojiPicker(msg.Id)">
                                        😀 React
                                    </button>
                                </div>

                                @if (_emojiPickerMessageId == msg.Id)
                                {
                                    <div class="emoji-picker">
                                        @foreach (var emoji in _commonEmojis)
                                        {
                                            <button class="emoji-option" @onclick="() => AddReactionFromPickerAsync(msg.Id, emoji)">
                                                @emoji
                                            </button>
                                        }
                                    </div>
                                }
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_newMessage" @bind:event="oninput"
                          placeholder="Type a message…"
                          @onkeydown="OnMessageKeyDown" rows="2"></textarea>
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(_newMessage)"
                        @onclick="SendMessageAsync">Send</button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ───── Right Panel: Thread View ───── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread">✕</button>
            </div>
            <div class="thread-root-quote">
                <span class="author">@_threadRootMessage.Author</span>
                <span class="timestamp">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                <p>@_threadRootMessage.Content</p>
            </div>

            <div class="thread-replies">
                @if (_threadMessages is not null)
                {
                    @foreach (var reply in _threadMessages)
                    {
                        <div class="message-row">
                            <div class="message-meta">
                                <span class="author">@reply.Author</span>
                                <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ToggleReactionAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_threadReply" @bind:event="oninput"
                          placeholder="Reply in thread…"
                          @onkeydown="OnThreadKeyDown" rows="2"></textarea>
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(_threadReply)"
                        @onclick="SendThreadReplyAsync">Reply</button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    // ── State ──
    private List<Channel>? _channels;
    private int _activeChannelId;
    private Channel? _activeChannel;
    private List<Message>? _messages;
    private Dictionary<int, ThreadSummary> _threadSummaries = new();
    private int _skip;
    private bool _loadingOlder;
    private bool _allOlderLoaded;
    private string _newMessage = "";

    // Thread panel
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;
    private string _threadReply = "";

    // Hover / picker
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0]);
        }
    }

    // ── Channel selection ──
    private async Task SelectChannelAsync(Channel channel)
    {
        _activeChannel = channel;
        _activeChannelId = channel.Id;
        _skip = 0;
        _allOlderLoaded = false;
        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _skip = _messages.Count;
        BuildThreadSummaries();
        CloseThread();
        await ChatService.MarkChannelReadAsync(channel.Id);
        await RefreshChannelList();
    }

    private async Task RefreshChannelList()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    // ── Pagination: load older on scroll-to-top ──
    private async Task OnMessageListScroll()
    {
        if (_loadingOlder || _allOlderLoaded || _activeChannel is null) return;

        var scrollTop = await JS.InvokeAsync<double>("chatScrollHelpers.getScrollTop", _messageListRef);
        if (scrollTop > 50) return;

        _loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannel.Id, _skip, PageSize);
        if (older.Count == 0)
        {
            _allOlderLoaded = true;
        }
        else
        {
            _messages = older.Concat(_messages!).ToList();
            _skip += older.Count;
            BuildThreadSummaries();
        }

        _loadingOlder = false;
    }

    // ── Send message ──
    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannel.Id, _newMessage.Trim(), null);
        _messages ??= new();
        _messages.Add(sent);
        _newMessage = "";

        await JS.InvokeVoidAsync("chatScrollHelpers.scrollToBottom", _messageListRef);
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ── Thread ──
    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadOpen = true;
        _emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = null;
        _threadReply = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReply) || _threadRootMessage is null || _activeChannel is null)
            return;

        var reply = await ChatService.SendMessageAsync(_activeChannel.Id, _threadReply.Trim(), _threadRootMessage.Id);
        _threadMessages ??= new();
        _threadMessages.Add(reply);
        _threadReply = "";

        // Update thread summary count in main view
        if (_threadSummaries.TryGetValue(_threadRootMessage.Id, out var existing))
        {
            _threadSummaries[_threadRootMessage.Id] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(_threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Reactions ──
    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionFromPickerAsync(int messageId, string emoji)
    {
        _emojiPickerMessageId = null;
        await ToggleReactionAsync(messageId, emoji);
    }

    private async Task ToggleReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh messages to show updated reactions
        if (_activeChannel is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannel.Id, 0, _skip > 0 ? _skip : PageSize);
        }

        if (_threadOpen && _threadRootMessage is not null)
        {
            _threadMessages = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    // ── Helpers ──
    private void BuildThreadSummaries()
    {
        if (_messages is null) return;

        // Messages with ReplyToId indicate they are replies; group by root to form summaries
        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
        var grouped = replies.GroupBy(m => m.ReplyToId!.Value);

        _threadSummaries = grouped.ToDictionary(
            g => g.Key,
            g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt))
        );
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
